import React, { useEffect } from 'react';
import Hero from './sections/Hero';
import Work from './sections/Work';
import Services from './sections/Services';
import Contact from './sections/Contact';
import Footer from './components/Footer';
import './App.css';

const LOGOS = [
  {
    name: 'Premiere Pro',
    short: 'Pr',
    style: { '--x': '8%', '--y': '18%', '--dur': '14s', '--delay': '-2s', '--amp': '24px' },
  },
  {
    name: 'After Effects',
    short: 'Ae',
    style: { '--x': '84%', '--y': '16%', '--dur': '18s', '--delay': '-6s', '--amp': '20px' },
  },
  {
    name: 'DaVinci Resolve',
    short: 'DaV',
    style: { '--x': '14%', '--y': '72%', '--dur': '20s', '--delay': '-9s', '--amp': '28px' },
  },
  {
    name: 'CapCut',
    short: 'Cc',
    style: { '--x': '78%', '--y': '66%', '--dur': '16s', '--delay': '-4s', '--amp': '22px' },
  },
  {
    name: 'Photoshop',
    short: 'Ps',
    style: { '--x': '46%', '--y': '84%', '--dur': '22s', '--delay': '-12s', '--amp': '26px' },
  },
];

function FloatingLogos() {
  return (
    <div className="floating-logos" aria-hidden="true">
      {LOGOS.map((logo) => (
        <div className="floating-logo" style={logo.style} key={logo.name}>
          <svg viewBox="0 0 64 64" role="img" aria-label={logo.name}>
            <rect x="3" y="3" width="58" height="58" rx="14" />
            <text x="50%" y="54%" textAnchor="middle" dominantBaseline="middle">
              {logo.short}
            </text>
          </svg>
        </div>
      ))}
    </div>
  );
}

export default function App() {
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('is-visible');
          }
        });
      },
      {
        threshold: 0.2,
        rootMargin: '0px 0px -12% 0px',
      }
    );

    document.querySelectorAll('.reveal-on-scroll').forEach((item) => observer.observe(item));

    return () => observer.disconnect();
  }, []);

  return (
    <div className="app-shell">
      <div className="ambient-bg" aria-hidden="true">
        <span className="orb orb-one" />
        <span className="orb orb-two" />
        <span className="orb orb-three" />
      </div>
      <FloatingLogos />

      <main className="main-content">
        <Hero />
        <Work />
        <Services />
        <Contact />
        <Footer />
      </main>
    </div>
  );
}
